#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K, x, D;
        scanf("%d %d %d %d", &N, &K, &x, &D);
        int p[K];
        for (int i = 0; i < K; i++) {
            scanf("%d", &p[i]);
        }
        long long total = 0;
        for (int i = 0; i < K; i++) {
            total += p[i];
        }
        int count = K;
        for (int i = 1; i <= x; i++) {
            int found = 0;
            for (int j = 0; j < K; j++) {
                if (abs(i - p[j]) <= D) {
                    found = 1;
                    break;
                }
            }
            if (found) {
                total += i;
                count++;
            }
            if (count == N) {
                break;
            }
        }
        if (count == N) {
            printf("%lld\n", total);
        } else {
            printf("-1\n");
        }
    }
    return 0;
}

