import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int x = sc.nextInt();
            int D = sc.nextInt();
            int[] p = new int[K];
            for (int i = 0; i < K; i++) {
                p[i] = sc.nextInt();
            }
            long total = 0;
            for (int i = 0; i < K; i++) {
                total += p[i];
            }
            int count = K;
            for (int i = 1; i <= x; i++) {
                int found = 0;
                for (int j = 0; j < K; j++) {
                    if (Math.abs(i - p[j]) <= D) {
                        found = 1;
                        break;
                    }
                }
                if (found) {
                    total += i;
                    count++;
                }
                if (count == N) {
                    break;
                }
            }
            if (count == N) {
                System.out.println(total);
